/**
 * The class for holding mesh triangle data.
 *
 * @ignore
 */
export class MeshTriData {
    constructor(mesh: any, priority?: number);
    /**
     * The priority of the triangle data (Used for intersection ordering).
     * priority = 0 - no priority
     * priority > 0 - higher value represents a higher priority
     *
     * @type {number}
     */
    _priority: number;
    /**
     * The transform of the mesh.
     *
     * @type {Mat4}
     */
    _ptm: Mat4;
    /**
     * The array of triangles for the mesh.
     *
     * @type {Tri[]}
     */
    tris: Tri[];
    get ptm(): Mat4;
    get priority(): number;
    _trisFromMesh(mesh: any, destroy?: boolean): Tri[];
    setTransform(pos?: Vec3, rot?: Quat, scale?: Vec3): void;
    setTris(mesh: any): void;
}
import { Mat4 } from '../..//core/math/mat4.js';
import { Tri } from '../../core/shape/tri.js';
import { Vec3 } from '../../core/math/vec3.js';
import { Quat } from '../../core/math/quat.js';
